export default `body{font-family:Segoe UI,sans-serif;margin:0;background:linear-gradient(135deg,#f0f4ff,#e6f7ff);color:#333}header{background:linear-gradient(90deg,#007bff,#00c6ff);color:#fff;padding:25px;text-align:center;font-size:1.8rem;font-weight:700;letter-spacing:1px;box-shadow:0 4px 10px #0003}.form-container{background:#fff;padding:30px;border-radius:12px;max-width:750px;margin:40px auto;box-shadow:0 8px 20px #0000001a;border:1px solid #e0e0e0}.form-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:20px}.form-container input{padding:12px;border:1px solid #ccc;border-radius:8px;font-size:15px;transition:border .3s}.form-container input:focus{border-color:#007bff;outline:none;box-shadow:0 0 5px #007bff4d}.form-container button{grid-column:span 2;background:linear-gradient(90deg,#28a745,#20c997);color:#fff;border:none;padding:14px;border-radius:8px;cursor:pointer;font-size:16px;font-weight:700;transition:transform .2s,background .3s}.form-container button:hover{transform:scale(1.03);background:linear-gradient(90deg,#218838,#17a589)}.hero-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:30px;max-width:1200px;margin:0 auto 50px;padding:0 20px}.hero-card{background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 8px 20px #0000001a;transition:transform .25s,box-shadow .25s}.hero-card:hover{transform:translateY(-8px);box-shadow:0 12px 25px #00000026}.hero-card img{width:100%;height:230px;object-fit:cover;background:#f9f9f9}.hero-content{padding:18px;text-align:center;cursor:pointer}.hero-content h3{margin:10px 0;color:#007bff;font-size:20px;font-weight:700}.hero-content p{margin:0;font-size:14px;color:#666}.btn-edit{background:linear-gradient(90deg,#007bff,#00a2ff);color:#fff;border:none;padding:10px 16px;border-radius:8px;cursor:pointer;font-size:14px;font-weight:700}.btn-delete{background:linear-gradient(90deg,#dc3545,#ff4d4d);color:#fff;border:none;padding:10px 16px;border-radius:8px;cursor:pointer;font-size:14px;font-weight:700}
`;